  1→// Cloudflare Durable Object for relay WebSocket multiplexing.
  2→// One DO per Deus server. Holds the server tunnel + all client connections.
  3→// Uses the WebSocket Hibernation API for efficient connection handling.
  4→// All mutable state lives in ctx.storage to survive hibernation.
  5→//
  6→// Storage keys:
  7→//   relayToken                   — server's relay token (set on first registration)
  8→//   tunnelRegistered             — boolean, true after successful register handshake
  9→//   serverDisconnectedAt         — timestamp when server disconnected (persists until reconnect)
 10→//   serverName                   — server name for display to clients
 11→//   pending:<clientId>           — auth deadline timestamp for pending clients
 12→//   auth_token:<clientId>        — client's device token (stored for re-forwarding on reconnect)
 13→//   pending:pair:<pairId>       — deadline timestamp for one-shot pairing requests
 14→
 15→import { DurableObject } from "cloudflare:workers";
 16→import type {
 17→  PairerFrame,
 18→  RelayClientFrame,
 19→  RelayFrame,
 20→  RelayPairerFrame,
 21→  ServerFrame,
 22→} from "../../../shared/types/relay";
 23→import { clientAuthFrameSchema, pairerFrameSchema, serverFrameSchema } from "./schemas";
 24→
 25→const AUTH_TIMEOUT_MS = 5_000;
 26→const OFFLINE_WAIT_MS = 300_000; // 5 min — max time a client waits for server to reconnect
 27→const HEARTBEAT_INTERVAL_MS = 30_000;
 28→const PAIR_TIMEOUT_MS = 30_000;
 29→
 30→export class RelayDO extends DurableObject {
 31→  async fetch(request: Request): Promise<Response> {
 32→    const url = new URL(request.url);
 33→
 34→    if (url.pathname === "/tunnel") {
 35→      return this.handleTunnel(request);
 36→    }
 37→    if (url.pathname === "/connect") {
 38→      return this.handleClient(request);
 39→    }
 40→    if (url.pathname === "/pair") {
 41→      return this.handlePairer(request);
 42→    }
 43→    if (url.pathname === "/status") {
 44→      return this.handleStatus();
 45→    }
 46→
 47→    return new Response("Not found", { status: 404 });
 48→  }
 49→
 50→  // ---- Server Tunnel ----
 51→
 52→  private async handleTunnel(request: Request): Promise<Response> {
 53→    // Authenticate BEFORE closing existing tunnels to prevent unauthenticated
 54→    // connections from disrupting a legitimate server's tunnel (DoS).
 55→    const storedToken = await this.ctx.storage.get<string>("relayToken");
 56→    if (storedToken) {
 57→      const url = new URL(request.url);
 58→      const token =
 59→        request.headers.get("Authorization")?.replace("Bearer ", "") ||
 60→        url.searchParams.get("token");
 61→      if (token !== storedToken) {
 62→        return new Response("Unauthorized", { status: 401 });
 63→      }
 64→    }
 65→
 66→    // Close any existing tunnel before accepting a new one to prevent
 67→    // stale connections from receiving messages meant for the new tunnel.
 68→    const existingTunnels = this.ctx.getWebSockets("tunnel");
 69→    for (const tunnel of existingTunnels) {
 70→      try {
 71→        tunnel.close(1000, "New tunnel connection");
 72→      } catch (err) {
 73→        console.error("relay: failed to close existing tunnel", err);
 74→      }
 75→    }
 76→
 77→    // New tunnel is not yet registered — must complete register handshake first
 78→    await this.ctx.storage.put("tunnelRegistered", false);
 79→
 80→    const pair = new WebSocketPair();
 81→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
 82→
 83→    this.ctx.acceptWebSocket(server, ["tunnel"]);
 84→
 85→    return new Response(null, { status: 101, webSocket: client });
 86→  }
 87→
 88→  // ---- Client Connection ----
 89→
 90→  private async handleClient(_request: Request): Promise<Response> {
 91→    const tunnels = this.ctx.getWebSockets("tunnel");
 92→    if (tunnels.length === 0) {
 93→      // Accept connections if server was ever registered — it may come back.
 94→      // Only reject for completely unknown servers (never registered).
 95→      const hasEverRegistered = await this.ctx.storage.get<string>("relayToken");
 96→      if (!hasEverRegistered) {
 97→        return Response.json({ error: "server_not_found" }, { status: 503 });
 98→      }
 99→    }
100→
101→    const pair = new WebSocketPair();
102→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
103→
104→    const clientId = crypto.randomUUID();
105→    // Tags are immutable after acceptWebSocket — don't encode mutable state in them.
106→    // Auth state is tracked via storage keys instead.
107→    this.ctx.acceptWebSocket(server, ["client", clientId]);
108→
109→    // Store auth deadline in durable storage (survives hibernation)
110→    await this.ctx.storage.put(`pending:${clientId}`, Date.now() + AUTH_TIMEOUT_MS);
111→    await this.scheduleNextAlarm();
112→
113→    return new Response(null, { status: 101, webSocket: client });
114→  }
115→
116→  // ---- Status ----
117→
118→  private async handleStatus(): Promise<Response> {
119→    const tunnels = this.ctx.getWebSockets("tunnel");
120→    const allClients = this.ctx.getWebSockets("client");
121→    const pendingClientCount = (await this.getPendingClients()).size;
122→    const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
123→    const serverName = await this.ctx.storage.get<string>("serverName");
124→
125→    return Response.json({
126→      online: tunnels.length > 0,
127→      clients: Math.max(0, allClients.length - pendingClientCount),
128→      reconnecting: serverDisconnectedAt !== undefined,
129→      serverDisconnectedAt: serverDisconnectedAt ?? null,
130→      serverName: serverName || null,
131→    });
132→  }
133→
134→  // ---- Pairing (one-shot code exchange) ----
135→
136→  private async handlePairer(_request: Request): Promise<Response> {
137→    // Pairing requires an active, registered server tunnel
138→    const tunnel = this.getTunnel();
139→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
140→    if (!tunnel || !isRegistered) {
141→      return Response.json({ error: "server_offline" }, { status: 503 });
142→    }
143→
144→    const pair = new WebSocketPair();
145→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
146→
147→    const pairId = crypto.randomUUID();
148→    this.ctx.acceptWebSocket(server, ["pairer", pairId]);
149→
150→    // Store deadline for cleanup via alarm
151→    await this.ctx.storage.put(`pending:pair:${pairId}`, Date.now() + PAIR_TIMEOUT_MS);
152→    await this.scheduleNextAlarm();
153→
154→    return new Response(null, { status: 101, webSocket: client });
155→  }
156→
157→  // ---- WebSocket Handlers (Hibernation API) ----
158→
159→  async webSocketMessage(ws: WebSocket, message: string | ArrayBuffer): Promise<void> {
160→    const tags = this.ctx.getTags(ws);
161→    const raw = typeof message === "string" ? message : new TextDecoder().decode(message);
162→
163→    let json: unknown;
164→    try {
165→      json = JSON.parse(raw);
166→    } catch {
167→      console.error("relay: failed to parse WebSocket message as JSON");
168→      return;
169→    }
170→
171→    if (tags.includes("tunnel")) {
172→      const result = serverFrameSchema.safeParse(json);
173→      if (!result.success) {
174→        console.error("relay: invalid server frame", result.error.issues);
175→        return;
176→      }
177→      // Cast is safe — Zod validated the shape, but its inferred type for pair_response
178→      // uses `success: boolean` while our ServerFrame uses discriminated `true | false`.
179→      await this.handleServerMessage(ws, result.data as ServerFrame);
180→    } else if (tags.includes("pairer")) {
181→      const pairId = tags.find((t) => t !== "pairer");
182→      if (!pairId) return;
183→      const result = pairerFrameSchema.safeParse(json);
184→      if (!result.success) {
185→        console.error("relay: invalid pairer frame", result.error.issues);
186→        return;
187→      }
188→      await this.handlePairerMessage(pairId, result.data);
189→    } else if (tags.includes("client")) {
190→      const clientId = tags.find((t) => t !== "client");
191→      if (!clientId) return;
192→      await this.handleClientMessage(clientId, json);
193→    }
194→  }
195→
196→  async webSocketClose(
197→    ws: WebSocket,
198→    _code: number,
199→    _reason: string,
200→    _wasClean: boolean
201→  ): Promise<void> {
202→    await this.handleWebSocketTermination(ws);
203→  }
204→
205→  async webSocketError(ws: WebSocket, _error: unknown): Promise<void> {
206→    await this.handleWebSocketTermination(ws);
207→  }
208→
209→  private async handleWebSocketTermination(ws: WebSocket): Promise<void> {
210→    const tags = this.ctx.getTags(ws);
211→
212→    if (tags.includes("tunnel")) {
213→      await this.handleServerDisconnect();
214→    } else if (tags.includes("pairer")) {
215→      const pairId = tags.find((t) => t !== "pairer");
216→      if (pairId) {
217→        await this.ctx.storage.delete(`pending:pair:${pairId}`);
218→      }
219→    } else if (tags.includes("client")) {
220→      const clientId = tags.find((t) => t !== "client");
221→      if (clientId) {
222→        await this.handleClientDisconnect(clientId);
223→      }
224→    }
225→  }
226→
227→  // ---- Alarm (auth timeout + heartbeat) ----
228→
229→  async alarm(): Promise<void> {
230→    const now = Date.now();
231→
232→    // 1. Reject clients whose auth deadline has expired
233→    const pendingClients = await this.getPendingClients();
234→    const expiredClientIds: string[] = [];
235→    for (const [clientId, deadline] of pendingClients) {
236→      if (now >= deadline) {
237→        expiredClientIds.push(clientId);
238→      }
239→    }
240→    if (expiredClientIds.length > 0) {
241→      const keysToDelete = expiredClientIds.flatMap((id) => [`pending:${id}`, `auth_token:${id}`]);
242→      await this.ctx.storage.delete(keysToDelete);
243→      for (const clientId of expiredClientIds) {
244→        this.rejectClient(clientId, "Authentication timeout");
245→      }
246→    }
247→
248→    // 1b. Reject pairers whose deadline has expired
249→    const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
250→    for (const [key, deadline] of pendingPairs) {
251→      if (now >= deadline) {
252→        const pairId = key.slice("pending:pair:".length);
253→        const pairerWs = this.findPairerWs(pairId);
254→        if (pairerWs) {
255→          this.safeSend(pairerWs, { type: "pair_failed", message: "Pairing timed out" });
256→          try {
257→            pairerWs.close(1000, "Pairing timed out");
258→          } catch (err) {
259→            console.error("relay: failed to close expired pairer", err);
260→          }
261→        }
262→        await this.ctx.storage.delete(key);
263→      }
264→    }
265→
266→    // 2. Send heartbeat ping to server
267→    const tunnel = this.getTunnel();
268→    if (tunnel) {
269→      this.safeSend(tunnel, { type: "ping" });
270→    }
271→
272→    // 3. Reschedule for next event
273→    await this.scheduleNextAlarm();
274→  }
275→
276→  // ---- Server Message Handling ----
277→
278→  private async handleServerMessage(ws: WebSocket, frame: ServerFrame): Promise<void> {
279→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
280→
281→    switch (frame.type) {
282→      case "register": {
283→        await this.handleRegister(ws, frame);
284→        break;
285→      }
286→      case "auth_response": {
287→        // Only registered tunnels may send auth_response
288→        if (!isRegistered) break;
289→        await this.handleAuthResponse(frame.clientId, frame.allowed, frame.reason);
290→        break;
291→      }
292→      case "pair_response": {
293→        if (!isRegistered) break;
294→        await this.ctx.storage.delete(`pending:pair:${frame.pairId}`);
295→        const pairerWs = this.findPairerWs(frame.pairId);
296→        if (!pairerWs) break;
297→        if (frame.success) {
298→          this.safeSend(pairerWs, { type: "pair_success", token: frame.deviceToken });
299→        } else {
300→          this.safeSend(pairerWs, { type: "pair_failed", message: frame.reason });
301→        }
302→        // Close the one-shot pairer WS — buffered messages are sent before the close frame
303→        try {
304→          pairerWs.close(1000, "Pairing complete");
305→        } catch (err) {
306→          console.error("relay: failed to close pairer after response", err);
307→        }
308→        break;
309→      }
310→      case "data": {
311→        // Only registered tunnels may send data
312→        if (!isRegistered) break;
313→        await this.forwardToClient(frame.clientId, frame.payload);
314→        break;
315→      }
316→      case "pong": {
317→        break;
318→      }
319→    }
320→  }
321→
322→  private async handleRegister(
323→    ws: WebSocket,
324→    frame: Extract<ServerFrame, { type: "register" }>
325→  ): Promise<void> {
326→    const storedToken = await this.ctx.storage.get<string>("relayToken");
327→    if (storedToken && storedToken !== frame.relayToken) {
328→      this.safeSend(ws, { type: "error", message: "Invalid relay token" });
329→      try {
330→        ws.close(4003, "Invalid relay token");
331→      } catch (err) {
332→        console.error("relay: failed to close tunnel with bad token", err);
333→      }
334→      return;
335→    }
336→
337→    if (!storedToken) {
338→      await this.ctx.storage.put("relayToken", frame.relayToken);
339→    }
340→
341→    // Always update server name (user might have changed it)
342→    if (frame.serverName) {
343→      await this.ctx.storage.put("serverName", frame.serverName);
344→    }
345→
346→    // Mark tunnel as registered — gates auth_response/data processing
347→    await this.ctx.storage.put("tunnelRegistered", true);
348→
349→    // Clear reconnection state and notify clients server is back
350→    const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
351→    await this.ctx.storage.delete("serverDisconnectedAt");
352→
353→    // Confirm registration to the WebSocket that sent it
354→    this.safeSend(ws, { type: "registered" });
355→
356→    // Notify already-authenticated clients that the server is back.
357→    // Pending clients are notified via the normal auth flow (they'll get "authenticated").
358→    if (wasReconnecting !== undefined) {
359→      const clients = this.ctx.getWebSockets("client");
360→      for (const clientWs of clients) {
361→        const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
362→        if (!clientId) continue;
363→        const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
364→        if (isPending !== undefined) continue;
365→        this.safeSend(clientWs, { type: "server_connected" });
366→      }
367→    }
368→
369→    // Always re-forward pending clients' stored auth tokens to the new tunnel.
370→    // This handles both reconnection (wasReconnecting) and tunnel replacement
371→    // (where serverDisconnectedAt was never set because the old tunnel's close
372→    // handler saw the new tunnel already existed).
373→    const pendingClients = await this.getPendingClients();
374→    for (const [pendingClientId] of pendingClients) {
375→      const storedAuthToken = await this.ctx.storage.get<string>(`auth_token:${pendingClientId}`);
376→      if (storedAuthToken) {
377→        this.safeSend(ws, {
378→          type: "client_connected",
379→          clientId: pendingClientId,
380→          deviceToken: storedAuthToken,
381→        });
382→      }
383→    }
384→
385→    // Start heartbeat
386→    await this.scheduleNextAlarm();
387→  }
388→
389→  // ---- Auth Delegation ----
390→
391→  private async handleAuthResponse(
392→    clientId: string,
393→    allowed: boolean,
394→    reason?: string
395→  ): Promise<void> {
396→    await this.ctx.storage.delete(`pending:${clientId}`);
397→    await this.ctx.storage.delete(`auth_token:${clientId}`);
398→
399→    if (allowed) {
400→      this.activateClient(clientId);
401→    } else {
402→      this.rejectClient(clientId, reason || "Authentication denied");
403→    }
404→  }
405→
406→  private activateClient(clientId: string): void {
407→    const ws = this.findClientWs(clientId);
408→    if (ws) {
409→      this.safeSend(ws, { type: "authenticated" });
410→    }
411→  }
412→
413→  private rejectClient(clientId: string, message: string): void {
414→    const ws = this.findClientWs(clientId);
415→    if (ws) {
416→      this.safeSend(ws, { type: "auth_failed", message });
417→      try {
418→        ws.close(4003, message);
419→      } catch (err) {
420→        console.error(`relay: failed to close rejected client ${clientId}`, err);
421→      }
422→    }
423→  }
424→
425→  // ---- Client Message Handling ----
426→
427→  private async handleClientMessage(clientId: string, json: unknown): Promise<void> {
428→    const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
429→
430→    if (isPending !== undefined) {
431→      // Client is still pending — only accept authenticate messages
432→      const authResult = clientAuthFrameSchema.safeParse(json);
433→      if (!authResult.success) return;
434→
435→      const { token } = authResult.data;
436→      // Store the token so we can re-forward it if the server reconnects
437→      await this.ctx.storage.put(`auth_token:${clientId}`, token);
438→
439→      const tunnel = this.getTunnel();
440→      const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
441→      if (tunnel && isRegistered) {
442→        this.safeSend(tunnel, {
443→          type: "client_connected",
444→          clientId,
445→          deviceToken: token,
446→        });
447→      } else if (tunnel) {
448→        // Tunnel exists but not yet registered — replacement in progress.
449→        // Leave client pending; handleRegister will re-forward the stored
450→        // auth token once the new tunnel completes registration.
451→        // The auth timeout alarm will reject naturally if registration never comes.
452→      } else {
453→        // Server tunnel is down — keep client waiting for server to return.
454→        // Suspend the short auth deadline; handleRegister will re-forward the
455→        // stored auth token when the server reconnects.
456→        const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
457→        await this.ctx.storage.put(`pending:${clientId}`, Date.now() + OFFLINE_WAIT_MS);
458→        const clientWs = this.findClientWs(clientId);
459→        if (clientWs) {
460→          const serverName = await this.ctx.storage.get<string>("serverName");
461→          this.safeSend(clientWs, {
462→            type: "server_reconnecting",
463→            serverDisconnectedAt: serverDisconnectedAt ?? Date.now(),
464→            serverName: serverName || null,
465→          });
466→        }
467→      }
468→      return;
469→    }
470→
471→    // Authenticated client — forward data to server
472→    const tunnel = this.getTunnel();
473→    if (tunnel) {
474→      this.safeSend(tunnel, {
475→        type: "data",
476→        clientId,
477→        payload: JSON.stringify(json),
478→      });
479→    }
480→  }
481→
482→  // ---- Pairer Message Handling ----
483→
484→  private async handlePairerMessage(pairId: string, frame: PairerFrame): Promise<void> {
485→    const isPending = await this.ctx.storage.get<number>(`pending:pair:${pairId}`);
486→    if (isPending === undefined) return;
487→
488→    const tunnel = this.getTunnel();
489→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
490→    if (tunnel && isRegistered) {
491→      this.safeSend(tunnel, {
492→        type: "pair_request",
493→        pairId,
494→        code: frame.code,
495→        deviceName: frame.deviceName,
496→      });
497→    } else {
498→      const pairerWs = this.findPairerWs(pairId);
499→      if (pairerWs) {
500→        this.safeSend(pairerWs, { type: "pair_failed", message: "Server is offline" });
501→        try {
502→          pairerWs.close(1000, "Server offline");
503→        } catch (err) {
504→          console.error("relay: failed to close pairer (server offline)", err);
505→        }
506→      }
507→      await this.ctx.storage.delete(`pending:pair:${pairId}`);
508→    }
509→  }
510→
511→  // ---- Client/Server Lifecycle ----
512→
513→  private async handleClientDisconnect(clientId: string): Promise<void> {
514→    await this.ctx.storage.delete(`pending:${clientId}`);
515→    await this.ctx.storage.delete(`auth_token:${clientId}`);
516→
517→    const tunnel = this.getTunnel();
518→    if (tunnel) {
519→      this.safeSend(tunnel, {
520→        type: "client_disconnected",
521→        clientId,
522→      });
523→    }
524→  }
525→
526→  private async handleServerDisconnect(): Promise<void> {
527→    // If another tunnel is already active (e.g. old tunnel's close callback firing
528→    // after handleTunnel replaced it), skip the disconnect flow.
529→    const tunnels = this.ctx.getWebSockets("tunnel");
530→    if (tunnels.length > 0) return;
531→
532→    const existing = await this.ctx.storage.get<number>("serverDisconnectedAt");
533→    if (existing !== undefined) return; // Already handling disconnect
534→
535→    await this.ctx.storage.put("tunnelRegistered", false);
536→    const disconnectedAt = Date.now();
537→    await this.ctx.storage.put("serverDisconnectedAt", disconnectedAt);
538→
539→    const serverName = await this.ctx.storage.get<string>("serverName");
540→    const clients = this.ctx.getWebSockets("client");
541→    for (const clientWs of clients) {
542→      this.safeSend(clientWs, {
543→        type: "server_reconnecting",
544→        serverDisconnectedAt: disconnectedAt,
545→        serverName: serverName || null,
546→      });
547→    }
548→
549→    await this.scheduleNextAlarm();
550→  }
551→
552→  // ---- Data Forwarding ----
553→
554→  private async forwardToClient(clientId: string, payload: string): Promise<void> {
555→    const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
556→    if (isPending !== undefined) {
557→      return;
558→    }
559→
560→    const ws = this.findClientWs(clientId);
561→    if (ws) {
562→      try {
563→        ws.send(payload);
564→      } catch (err) {
565→        console.error(`relay: failed to forward data to client ${clientId}`, err);
566→      }
567→    }
568→  }
569→
570→  // ---- Alarm Scheduling ----
571→
572→  private async scheduleNextAlarm(): Promise<void> {
573→    const now = Date.now();
574→    const candidates: number[] = [];
575→
576→    // All pending deadlines (clients + pairs share the "pending:" prefix)
577→    const allPending = await this.ctx.storage.list<number>({ prefix: "pending:" });
578→    for (const [, deadline] of allPending) {
579→      candidates.push(deadline);
580→    }
581→
582→    // Heartbeat interval (only if server is connected)
583→    if (this.ctx.getWebSockets("tunnel").length > 0) {
584→      candidates.push(now + HEARTBEAT_INTERVAL_MS);
585→    }
586→
587→    if (candidates.length > 0) {
588→      const nextAlarm = Math.min(...candidates);
589→      await this.ctx.storage.setAlarm(Math.max(nextAlarm, now + 100));
590→    }
591→  }
592→
593→  // ---- Helpers ----
594→
595→  /** Get pending client auth entries, filtering out pair entries that share the prefix. */
596→  private async getPendingClients(): Promise<Map<string, number>> {
597→    const entries = await this.ctx.storage.list<number>({ prefix: "pending:" });
598→    const result = new Map<string, number>();
599→    for (const [key, deadline] of entries) {
600→      if (key.startsWith("pending:pair:")) continue;
601→      result.set(key.slice("pending:".length), deadline);
602→    }
603→    return result;
604→  }
605→
606→  private findWs(group: string, id: string): WebSocket | null {
607→    for (const ws of this.ctx.getWebSockets(group)) {
608→      if (this.ctx.getTags(ws).includes(id)) return ws;
609→    }
610→    return null;
611→  }
612→
613→  private findClientWs(clientId: string): WebSocket | null {
614→    return this.findWs("client", clientId);
615→  }
616→
617→  private findPairerWs(pairId: string): WebSocket | null {
618→    return this.findWs("pairer", pairId);
619→  }
620→
621→  private getTunnel(): WebSocket | null {
622→    const tunnels = this.ctx.getWebSockets("tunnel");
623→    return tunnels[0] ?? null;
624→  }
625→
626→  private safeSend(ws: WebSocket, data: RelayFrame | RelayClientFrame | RelayPairerFrame): void {
627→    try {
628→      ws.send(JSON.stringify(data));
629→    } catch (err) {
630→      console.error("relay: safeSend failed", err);
631→    }
632→  }
633→}
