323→    ws: WebSocket,
324→    frame: Extract<ServerFrame, { type: "register" }>
325→  ): Promise<void> {
326→    const storedToken = await this.ctx.storage.get<string>("relayToken");
327→    if (storedToken && storedToken !== frame.relayToken) {
328→      this.safeSend(ws, { type: "error", message: "Invalid relay token" });
329→      try {
330→        ws.close(4003, "Invalid relay token");
331→      } catch (err) {
332→        console.error("relay: failed to close tunnel with bad token", err);
333→      }
334→      return;
335→    }
336→
337→    if (!storedToken) {
338→      await this.ctx.storage.put("relayToken", frame.relayToken);
339→    }
340→
341→    // Always update server name (user might have changed it)
342→    if (frame.serverName) {
343→      await this.ctx.storage.put("serverName", frame.serverName);
344→    }
345→
346→    // Mark tunnel as registered — gates auth_response/data processing
347→    await this.ctx.storage.put("tunnelRegistered", true);
348→
349→    // Clear reconnection state and notify clients server is back
350→    const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
351→    await this.ctx.storage.delete("serverDisconnectedAt");
352→
353→    // Confirm registration to the WebSocket that sent it
354→    this.safeSend(ws, { type: "registered" });
355→
356→    // Notify already-authenticated clients that the server is back.
357→    // Pending clients are notified via the normal auth flow (they'll get "authenticated").
358→    if (wasReconnecting !== undefined) {
359→      const clients = this.ctx.getWebSockets("client");
360→      for (const clientWs of clients) {
361→        const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
362→        if (!clientId) continue;
363→        const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
364→        if (isPending !== undefined) continue;
365→        this.safeSend(clientWs, { type: "server_connected" });
366→      }
367→    }
368→
369→    // Always re-forward pending clients' stored auth tokens to the new tunnel.
370→    // This handles both reconnection (wasReconnecting) and tunnel replacement
371→    // (where serverDisconnectedAt was never set because the old tunnel's close
372→    // handler saw the new tunnel already existed).
373→    const pendingClients = await this.getPendingClients();
374→    for (const [pendingClientId] of pendingClients) {
375→      const storedAuthToken = await this.ctx.storage.get<string>(`auth_token:${pendingClientId}`);
376→      if (storedAuthToken) {
377→        this.safeSend(ws, {
378→          type: "client_connected",
379→          clientId: pendingClientId,
380→          deviceToken: storedAuthToken,
381→        });
382→      }
383→    }
384→
385→    // Start heartbeat
386→    await this.scheduleNextAlarm();
387→  }
