  1→import { useState, useRef, useEffect, useCallback } from "react";
  2→import { QRCodeSVG } from "qrcode.react";
  3→import { Label } from "@/components/ui/label";
  4→import { Badge } from "@/components/ui/badge";
  5→import { Button } from "@/components/ui/button";
  6→import { Switch } from "@/components/ui/switch";
  7→import { Separator } from "@/components/ui/separator";
  8→import {
  9→  Dialog,
 10→  DialogContent,
 11→  DialogHeader,
 12→  DialogTitle,
 13→  DialogDescription,
 14→} from "@/components/ui/dialog";
 15→import { toast } from "sonner";
 16→import { Copy, Trash2, Smartphone, Monitor, Plus, Check, Link2 } from "lucide-react";
 17→import {
 18→  usePairedDevices,
 19→  useGeneratePairCode,
 20→  useRevokeDevice,
 21→  useRelayStatus,
 22→} from "../../api/auth.queries";
