 62→/**
 63→ * Portal URL card with connection status.
 64→ */
 65→function PortalCard({
 66→  url,
 67→  connected,
 68→  clients,
 69→}: {
 70→  url: string;
 71→  connected: boolean;
 72→  clients: number;
 73→}) {
 74→  return (
 75→    <div className="border-border/60 bg-muted/30 space-y-3 rounded-xl border px-4 py-4">
 76→      {/* Status line */}
 77→      <div className="flex items-center gap-2.5">
 78→        <span
 79→          className={`size-[7px] shrink-0 rounded-full ${
 80→            connected
 81→              ? "bg-success shadow-[0_0_6px_oklch(0.53_0.16_155/0.35)]"
 82→              : "bg-destructive/60"
 83→          }`}
 84→        />
 85→        <span className="text-muted-foreground text-xs font-medium">
 86→          {connected ? "Connected" : "Connecting..."}
 87→        </span>
 88→        {connected && clients > 0 && (
 89→          <span className="text-muted-foreground/70 text-[11px]">
 90→            &middot; {clients} {clients === 1 ? "device" : "devices"} online
 91→          </span>
 92→        )}
 93→      </div>
 94→
 95→      {/* URL + actions */}
 96→      <div className="flex items-center gap-2">
 97→        <p className="min-w-0 flex-1 truncate font-mono text-sm leading-relaxed">{url}</p>
 98→        <Button
 99→          variant="ghost"
100→          size="icon"
101→          className="size-7 shrink-0"
102→          onClick={async () => {
103→            try {
104→              await navigator.clipboard.writeText(url);
105→              toast.success("URL copied");
106→            } catch {
107→              toast.error("Couldn't copy the URL");
108→            }
109→          }}
110→          title="Copy URL"
111→        >
112→          <Copy className="size-3.5" />
113→        </Button>
114→      </div>
115→    </div>
116→  );
117→}
