298→/**
299→ * Connected devices list with remove action per device.
300→ */
301→function DevicesList({
302→  devices,
303→  onRemove,
304→  isRemoving,
305→}: {
306→  devices: PairedDevice[];
307→  onRemove: (device: PairedDevice) => void;
308→  isRemoving: boolean;
309→}) {
310→  if (devices.length === 0) {
311→    return <p className="text-muted-foreground py-0.5 text-sm">No devices connected yet.</p>;
312→  }
313→
314→  return (
315→    <div className="space-y-1.5">
316→      {devices.map((device) => {
317→        const DeviceIcon = getDeviceIcon(device.user_agent);
318→        return (
319→          <div
320→            key={device.id}
321→            className="bg-muted/30 flex items-center justify-between rounded-lg px-4 py-2.5"
322→          >
323→            <div className="flex items-center gap-3">
324→              <DeviceIcon className="text-muted-foreground size-4 shrink-0" />
325→              <div>
326→                <p className="text-sm font-medium">{device.name}</p>
327→                <p className="text-muted-foreground text-xs">
328→                  {timeAgo(device.last_seen_at)}
329→                  {device.ip_address ? ` \u00b7 ${device.ip_address}` : ""}
330→                </p>
331→              </div>
332→            </div>
333→            <Button
334→              variant="ghost"
335→              size="icon"
336→              className="text-muted-foreground hover:text-destructive size-7"
337→              onClick={() => onRemove(device)}
338→              disabled={isRemoving}
339→              title={`Remove ${device.name}`}
340→            >
341→              <Trash2 className="size-3.5" />
342→            </Button>
343→          </div>
344→        );
345→      })}
346→    </div>
347→  );
348→}
