350→// ---------------------------------------------------------------------------
351→// Main Section
352→// ---------------------------------------------------------------------------
353→
354→/**
355→ * Unified Access settings section.
356→ *
357→ * Hierarchy:
358→ *   1. Toggle + hero portal card (URL, status, copy)
359→ *   2. "+ Connect a Device" button that opens a dialog with QR + code
360→ *   3. Connected devices list
361→ */
362→export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
363→  const enabled = settings.remote_access_enabled === true;
364→
365→  // Remote access queries -- only active when enabled
366→  const devicesQuery = usePairedDevices(enabled);
367→  const relayQuery = useRelayStatus(enabled);
368→  const generateCodeMutation = useGeneratePairCode();
369→  const revokeDeviceMutation = useRevokeDevice();
370→
371→  // Dialog state
372→  const [dialogOpen, setDialogOpen] = useState(false);
373→
374→  // Code state -- lives here so it survives dialog close/reopen
375→  const [pairCode, setPairCode] = useState<string | null>(null);
376→  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
377→  const [countdown, setCountdown] = useState(0);
378→
379→  // Countdown timer -- runs regardless of dialog open state
380→  useEffect(() => {
381→    if (!pairCode || codeExpiresAt <= 0) return;
382→    const tick = () => {
383→      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
384→      setCountdown(remaining);
385→      if (remaining <= 0) {
386→        setPairCode(null);
387→        setCodeExpiresAt(0);
388→      }
389→    };
390→    tick();
391→    const interval = setInterval(tick, 1000);
392→    return () => clearInterval(interval);
393→  }, [pairCode, codeExpiresAt]);
394→
395→  async function handleGenerateCode() {
396→    try {
397→      const result = await generateCodeMutation.mutateAsync();
398→      setPairCode(result.code);
399→      setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
400→    } catch {
401→      toast.error("Couldn't generate a code. Try again.");
402→    }
403→  }
404→
405→  // -- Handlers --
406→
407→  const handleToggle = useCallback(
408→    async (on: boolean) => {
409→      const ok = await saveSetting("remote_access_enabled", on);
410→      if (ok) {
411→        toast.success(on ? "Device connections enabled" : "Device connections disabled");
412→      }
413→    },
414→    [saveSetting]
415→  );
416→
417→  async function handleRemoveDevice(device: PairedDevice) {
418→    try {
419→      await revokeDeviceMutation.mutateAsync(device.id);
420→      toast.success(`Removed "${device.name}"`);
421→    } catch {
422→      toast.error("Couldn't remove device. Try again.");
423→    }
424→  }
425→
426→  // -- Derived values --
427→
428→  const relayStatus = relayQuery.data;
429→  const devices = devicesQuery.data ?? [];
430→
431→  // Derive web app URL from relay WebSocket URL
432→  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
433→  const accessUrl = (() => {
434→    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
435→    try {
436→      const url = new URL(relayStatus.relayUrl);
437→      const host = url.hostname;
438→      const domain = host.replace(/^relay\./, "app.");
439→      return `https://${domain}/connect/${relayStatus.serverId}`;
440→    } catch {
441→      return null;
442→    }
443→  })();
444→
445→  // -- Render --
446→
447→  return (
448→    <div className="space-y-6">
449→      {/* Header */}
450→      <div>
451→        <h3 className="text-base font-semibold">Remote Access</h3>
452→        <p className="text-muted-foreground mt-1 text-sm">
453→          Access your workspaces from your phone or another computer.
454→        </p>
455→      </div>
456→
457→      {/* Master toggle */}
458→      <div className="flex items-center justify-between">
459→        <div>
460→          <Label htmlFor="remote-access-toggle" className="text-sm">
461→            Enable remote access
462→          </Label>
463→          <p className="text-muted-foreground text-xs">
464→            Allow other devices to connect to this machine.
465→          </p>
466→        </div>
467→        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
468→      </div>
469→
470→      {/* ----- Everything below is gated on the toggle ----- */}
471→
472→      {enabled && (
473→        <>
474→          {/* Portal card -- hero element: URL + status */}
475→          {accessUrl && relayStatus && (
476→            <PortalCard
477→              url={accessUrl}
478→              connected={relayStatus.connected}
479→              clients={relayStatus.clients}
480→            />
481→          )}
482→
483→          {/* Disconnected state without URL */}
484→          {relayStatus && !accessUrl && (
485→            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
486→              <span className="bg-warning size-[7px] shrink-0 rounded-full" />
487→              <span className="text-muted-foreground text-sm">
488→                {relayStatus.connected ? "Setting up..." : "Connecting..."}
489→              </span>
490→            </div>
491→          )}
492→
493→          <Separator />
494→
495→          {/* Connect a Device button */}
