import { Hono } from "hono";
import { getAllSettings, saveSetting } from "../services/settings.service";
import { parseBody, SaveSettingBody } from "../lib/schemas";
import { ensureRelayConnected, disconnectFromRelay } from "../services/relay.service";
import { checkAuth, isConnected } from "../services/agent";

const app = new Hono();

app.get("/settings", (c) => {
  return c.json(getAllSettings());
});

app.post("/settings", async (c) => {
  const { key, value } = parseBody(SaveSettingBody, await c.req.json());
  saveSetting(key, value);

  if (key === "remote_access_enabled") {
    if (value === true) {
      ensureRelayConnected();
    } else {
      disconnectFromRelay();
    }
  }

  return c.json({ success: true, key, value });
});

// Check agent provider auth status (Claude / Codex)
app.get("/settings/agent-auth", async (c) => {
  if (!isConnected()) {
    return c.json({ claude: null, codex: null, error: "Agent server not connected" });
  }

  const cwd = process.cwd();
  const [claudeResult, codexResult] = await Promise.allSettled([
    checkAuth({ agentType: "claude", cwd }),
    checkAuth({ agentType: "codex", cwd }),
  ]);

  return c.json({
    claude: claudeResult.status === "fulfilled" ? claudeResult.value : { error: String(claudeResult.reason) },
    codex: codexResult.status === "fulfilled" ? codexResult.value : { error: String(codexResult.reason) },
  });
});

export default app;

