  1→import { useEffect } from "react";
  2→import { match } from "ts-pattern";
  3→import { toast } from "sonner";
  4→import { Loader2 } from "lucide-react";
  5→import { getErrorMessage } from "@shared/lib/errors";
  6→import { SidebarInset } from "@/components/ui/sidebar";
  7→import { ScrollArea } from "@/components/ui/scroll-area";
  8→import { useTheme } from "@/app/providers";
  9→import { useUIStore } from "@/shared/stores/uiStore";
 10→import {
 11→  useSettings,
 12→  useUpdateSettings,
 13→} from "../api/settings.queries";
 14→import {
 15→  GeneralSection,
 16→  AISection,
 17→  EnvironmentSection,
 18→  ExperimentalSection,
 19→  AccessSection,
 20→  UpdateSection,
 21→} from "./sections";
 22→
 23→export function SettingsPage() {
 24→  const activeSection = useUIStore((s) => s.activeSettingsSection);
 25→  const closeSettings = useUIStore((s) => s.closeSettings);
 26→  const { theme, setTheme } = useTheme();
 27→
 28→  const settingsQuery = useSettings();
 29→  const updateSettingsMutation = useUpdateSettings();
 30→
 31→  const settings = settingsQuery.data || {};
 32→  const loading =
 33→    activeSection === "environment"
 34→      ? false // EnvironmentSection manages its own loading state
 35→      : settingsQuery.isLoading;
 36→  const saving = updateSettingsMutation.isPending;
 37→
 38→  // ESC closes settings
 39→  useEffect(() => {
 40→    function handleKeyDown(e: KeyboardEvent) {
 41→      if (e.key !== "Escape") return;
 42→      // Don't close if focus is in an input
 43→      const ae = document.activeElement as HTMLElement | null;
 44→      if (
 45→        ae &&
 46→        (ae.tagName === "INPUT" ||
 47→          ae.tagName === "TEXTAREA" ||
 48→          ae.isContentEditable ||
 49→          ae.getAttribute("role") === "textbox")
 50→      )
 51→        return;
 52→      closeSettings();
 53→    }
 54→
 55→    window.addEventListener("keydown", handleKeyDown);
 56→    return () => window.removeEventListener("keydown", handleKeyDown);
 57→  }, [closeSettings]);
 58→
 59→  async function saveSetting(key: string, value: unknown): Promise<boolean> {
 60→    try {
 61→      await updateSettingsMutation.mutateAsync({ [key]: value });
 62→      return true;
 63→    } catch (error) {
 64→      console.error("Failed to save setting:", error);
 65→      toast.error(`Failed to save setting: ${getErrorMessage(error)}`);
 66→      return false;
 67→    }
 68→  }
 69→
 70→  function renderContent() {
 71→    if (loading) {
 72→      return (
 73→        <div className="flex h-80 items-center justify-center">
 74→          <Loader2 className="text-muted-foreground size-5 animate-spin" />
 75→        </div>
 76→      );
 77→    }
 78→
 79→    const sectionProps = { settings, saveSetting };
 80→
 81→    return match(activeSection)
 82→      .with("general", () => <GeneralSection {...sectionProps} theme={theme} setTheme={setTheme} />)
 83→      .with("ai", () => <AISection {...sectionProps} />)
 84→      .with("environment", () => <EnvironmentSection />)
 85→      .with("experimental", () => <ExperimentalSection {...sectionProps} />)
 86→      .with("access", () => <AccessSection {...sectionProps} />)
 87→      .with("updates", () => <UpdateSection />)
 88→      .exhaustive();
 89→  }
 90→
