 54→/**
 55→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 56→ * Must be rendered inside SidebarProvider to access sidebar open state.
 57→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 58→ */
 59→function SidebarResizeHandle({
 60→  onSizeChange,
 61→  onDraggingChange,
 62→}: {
 63→  onSizeChange: (size: number | null) => void;
 64→  onDraggingChange: (dragging: boolean) => void;
 65→}) {
 66→  const { open } = useSidebar();
 67→
 68→  const { handleProps, isDragging } = useResizeHandle({
 69→    onSizeChange,
 70→    enabled: open,
 71→    direction: "horizontal",
 72→    mode: "primary",
 73→    minPrimarySize: 200,
 74→    minSecondarySize: 400,
 75→  });
 76→
 77→  // Notify parent of drag state changes to disable sidebar transitions
 78→  useEffect(() => {
 79→    onDraggingChange(isDragging);
 80→  }, [isDragging, onDraggingChange]);
 81→
 82→  if (!open) return null;
 83→
 84→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 85→}
