 87→export function MainLayout() {
 88→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 89→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 90→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 91→  const expandRepo = useSidebarStore((s) => s.expandRepo);
 92→
 93→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 94→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 95→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 96→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 97→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 98→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 99→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
100→
101→  // TanStack Query
102→  const workspacesQuery = useWorkspacesByRepo();
103→
104→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
105→  const loading = workspacesQuery.isLoading;
106→
107→  // Derive the full workspace object from React Query data.
108→  // The store only holds an ID; this useMemo resolves it to a Workspace
109→  // on every React Query refresh, eliminating the old sync effect entirely.
110→  const selectedWorkspace = useMemo(() => {
111→    if (!selectedWorkspaceId || !repoGroups.length) return null;
112→    for (const group of repoGroups) {
113→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
114→      if (found) return found;
115→    }
116→    return null;
117→  }, [selectedWorkspaceId, repoGroups]);
118→
119→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
120→  useEffect(() => {
121→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
122→  });
123→
124→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
125→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
126→
127→  // Sidebar resize: null = default 344px, number = user-set width
128→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
129→  // Tracks drag state to disable sidebar CSS transitions during resize
130→  const [sidebarDragging, setSidebarDragging] = useState(false);
131→
132→  // GitHub picker modal state
133→  const [githubPickerRepoId, setGithubPickerRepoId] = useState<string | null>(null);
134→
135→  // Ref for inserting text from browser element selector
136→  const workspaceChatPanelRef = useRef<SessionPanelRef | null>(null);
137→
138→  // Queries for repos, settings
139→  const reposQuery = useRepos();
140→  const settingsQuery = useSettingsQuery();
141→
142→  const repos = reposQuery.data || [];
143→  const username = settingsQuery.data?.user_name || "My Account";
144→
145→  // GitHub CLI status — gates PR polling
146→  const ghStatusQuery = useGhStatus();
147→
148→  // PR status query — gated on gh CLI, polls while agent is working
149→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
150→    ghInstalled: ghStatusQuery.data?.isInstalled,
151→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
152→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
153→  });
154→
155→  // --- Extracted hooks ---
156→
157→  const repoActions = useRepoActions({
158→    selectWorkspace,
159→    openNewWorkspaceModal,
160→    closeNewWorkspaceModal,
161→  });
162→
163→  // Derive repo name for GitHub picker modal from repoGroups
164→  const githubPickerRepoName = useMemo(() => {
165→    if (!githubPickerRepoId) return "";
166→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
167→    return group?.repo_name ?? "";
168→  }, [githubPickerRepoId, repoGroups]);
169→
170→  // Hide native WebContentsViews when any dialog is open — they render above
171→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
172→  // effect handles re-showing when the dialog closes.
173→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
174→  const anyDialogOpen =
175→    showNewWorkspaceModal ||
176→    showSystemPromptModal ||
177→    commandPaletteOpen ||
178→    !!githubPickerRepoId ||
179→    repoActions.showCloneModal;
180→  useEffect(() => {
181→    if (anyDialogOpen) {
182→      native.browserViews.hideAll().catch(() => {});
183→    }
184→  }, [anyDialogOpen]);
185→
186→  // --- System prompt (inline — small scope, one modal) ---
187→
188→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
189→  const updateSystemPromptMutation = useUpdateSystemPrompt();
190→  // Track user edits separately; reset to null when modal closes so the
191→  // derived value from the query takes over again (no useEffect + setState).
192→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
193→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
194→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
195→
196→  async function saveSystemPrompt() {
197→    if (!selectedWorkspace) return;
198→    try {
199→      await updateSystemPromptMutation.mutateAsync({
200→        workspaceId: selectedWorkspace.id,
201→        systemPrompt: systemPromptDraft,
202→      });
203→      closeSystemPromptModal();
204→      setSystemPromptEdit(null);
205→    } catch (error) {
206→      console.error("Failed to save system prompt:", error);
207→      toast.error(getErrorMessage(error));
208→    }
209→  }
210→
211→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
212→
213→  const archiveWorkspaceMutation = useArchiveWorkspace();
214→  const unarchiveMutation = useUnarchiveWorkspace();
215→
216→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
217→  // change frequently (every render / every workspace click), so we capture
218→  // them in refs to keep the callback identity stable. This matters because
219→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
220→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
221→  const unarchiveMutationRef = useRef(unarchiveMutation);
222→  const selectedWorkspaceRef = useRef(selectedWorkspace);
223→  useEffect(() => {
224→    archiveMutationRef.current = archiveWorkspaceMutation;
225→    unarchiveMutationRef.current = unarchiveMutation;
226→    selectedWorkspaceRef.current = selectedWorkspace;
227→  });
228→
229→  const archiveWorkspace = useCallback(
230→    async (workspaceId: string) => {
231→      try {
232→        await archiveMutationRef.current.mutateAsync(workspaceId);
233→        if (selectedWorkspaceRef.current?.id === workspaceId) {
234→          selectWorkspace(null);
235→        }
236→        toast("Workspace archived", {
237→          duration: 5000,
238→          action: {
239→            label: "Undo",
240→            onClick: () => {
241→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
242→                toast.error(getErrorMessage(error));
243→              });
244→            },
245→          },
246→        });
247→      } catch (error) {
248→        console.error("Error archiving workspace:", error);
249→        toast.error(getErrorMessage(error));
250→      }
251→    },
252→    [selectWorkspace]
253→  );
254→
255→  // --- Workflow status change (ref-stable like archive) ---
256→
257→  const statusMutation = useUpdateWorkspaceStatus();
258→  const statusMutationRef = useRef(statusMutation);
259→  useEffect(() => {
260→    statusMutationRef.current = statusMutation;
261→  });
262→
263→  const handleStatusChange = useCallback(
264→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
265→      statusMutationRef.current.mutate(
266→        { workspaceId, status },
267→        { onError: (error) => toast.error(getErrorMessage(error)) }
268→      );
269→    },
270→    []
271→  );
272→
273→  // --- Global hooks ---
274→
275→  // Connection state machine — subscribes to WS changes + send-attempt-failed events
276→  useConnectionStateInit();
277→
278→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
279→  useZoom();
280→
281→  // Track fullscreen state — toggles `.fullscreen` class on <html> for CSS
282→  useIsFullscreen();
283→
284→  // Adds .electron class to <html> and injects CSS-only drag region rules.
285→  // Headers with .drag-region class become draggable; buttons auto-excluded.
286→  useWindowDragZone();
287→
288→  // Disable CSS transitions during native window resize to prevent content "sticking"
289→  useWindowResizing();
290→
291→  function openInLastApp() {
292→    const lastAppId = getLastOpenInAppId();
293→    const path = selectedWorkspace?.workspace_path;
294→    if (lastAppId && path) {
295→      track("open_in_app", { app_id: lastAppId });
296→      native.apps.openIn(lastAppId, path).catch(() => {});
297→    }
298→  }
299→
300→  // Keyboard shortcuts
301→  useKeyboardShortcuts({
302→    onRefresh: async () => {
303→      workspacesQuery.refetch();
304→      if (selectedWorkspace) {
305→        prStatusQuery.refetch();
306→      }
307→    },
308→    onEscape: () => {
309→      if (showNewWorkspaceModal) {
310→        closeNewWorkspaceModal();
311→      } else if (showSystemPromptModal) {
312→        closeSystemPromptModal();
313→      }
314→    },
315→    onOpenInApp: capabilities.openInExternalApp ? openInLastApp : undefined,
316→    selectedWorkspace,
317→    modalStates: {
318→      showNewWorkspaceModal,
319→      showSystemPromptModal,
320→    },
321→  });
322→
323→  // Subscribe to chatInsertStore for content dispatched from BrowserPanel / DiffViewer / SimulatorPanel
324→  useEffect(() => {
325→    const unsubStore = useChatInsertStore.subscribe((state, prevState) => {
326→      if (!state.pending || state.pending === prevState.pending) return;
327→
328→      const payload = state.pending;
329→      chatInsertActions.consume();
330→
331→      if (!workspaceChatPanelRef.current) return;
332→      if (!isChatInsertForWorkspace(payload, selectedWorkspaceIdRef.current)) return;
333→
334→      deliverChatInsertPayload(workspaceChatPanelRef.current, payload);
335→    });
336→
337→    const unlistenChat = native.events.on(CHAT_INSERT, (data) => {
338→      void deserializeChatInsertPayload(data)
339→        .then((payload) => {
340→          chatInsertActions.dispatch(payload);
341→        })
342→        .catch((error) => {
343→          console.error("Failed to deserialize detached chat insert:", error);
344→        });
345→    });
346→
347→    return () => {
348→      unsubStore();
349→      unlistenChat();
350→    };
351→  }, []);
352→
353→  const handleWorkspaceClick = useCallback(
354→    (workspace: Workspace) => {
355→      selectWorkspace(workspace.id);
356→      expandRepo(workspace.repository_id);
357→      // Only mark the active tab's session as read — other tabs keep their
358→      // unread dots until the user actually switches to them.
359→      const layout = workspaceLayoutActions.getLayout(workspace.id);
360→      const activeSessionId = layout.activeChatTabSessionId || workspace.current_session_id;
361→      if (activeSessionId) {
362→        unreadActions.markRead(activeSessionId);
363→      }
364→    },
365→    [selectWorkspace, expandRepo]
366→  );
367→
368→  return (
369→    <SidebarProvider
370→      className="h-full"
371→      data-resizing={sidebarDragging || undefined}
372→      style={
373→        {
374→          "--sidebar-width": sidebarWidth ? `${sidebarWidth}px` : "344px",
375→          "--sidebar-width-mobile": "344px",
376→        } as React.CSSProperties
377→      }
378→    >
379→      {/* Sidebar — swap between app sidebar and settings sidebar */}
380→      {settingsOpen ? (
381→        <SettingsSidebar />
382→      ) : loading ? (
383→        <SidebarSkeleton />
384→      ) : (
385→        <AppSidebar
386→          repositories={repoGroups}
387→          selectedWorkspaceId={selectedWorkspace?.id || null}
388→          diffStatsMap={bulkDiffStatsQuery.data}
389→          onWorkspaceClick={handleWorkspaceClick}
390→          onNewWorkspace={repoActions.handleNewWorkspace}
391→          onNewWorkspaceFromGitHub={setGithubPickerRepoId}
392→          onAddRepository={repoActions.handleOpenProject}
393→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
394→          onArchive={archiveWorkspace}
395→          onStatusChange={handleStatusChange}
396→          profile={{ username }}
397→        />
398→      )}
399→
400→      {/* Sidebar resize handle */}
401→      <SidebarResizeHandle onSizeChange={setSidebarWidth} onDraggingChange={setSidebarDragging} />
402→
403→      {/* Main Content — swap between app content and settings page */}
404→      {settingsOpen ? (
405→        <SettingsPage />
406→      ) : (
407→        <MainContent
408→          selectedWorkspace={selectedWorkspace}
